        }

        return try {
            // Parse the uploaded file
            val bundleJson = file.inputStream.use { it.readBytes() }
            val bundle = objectMapper.readValue(bundleJson, ConfigBundleDto::class.java)

            // Parse options if provided
            val options = optionsJson?.let {
